import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { Subheader, SimpleListBoard, ContactUsForm } from '../../../../includes';
import { Grid } from '@material-ui/core';
import { inovateOSUtil, inovateOSUtilStrings } from '../../utils';
import { inovateOSPageActions } from '../actions';

const style = theme => ({
    root: {
        backgroundColor : inovateOSUtil.getTheme().gainboro,
    },
    subheader : {},
    subContainer : {},
    container : {
        margin : "100px 20px",
    },
    header : {
        color : inovateOSUtil.getTheme().secondary,
    },
    send : {
        backgroundColor : inovateOSUtil.getTheme().primary,
        color : inovateOSUtil.getTheme().white,
        "&:hover" : {
            backgroundColor : inovateOSUtil.getTheme().primary,
        }
    },
    contactInfo : {
        [theme.breakpoints.down("xs")] : {
            marginBottom : 50
        }
    }
})
class _InovateOSContactUs extends Component {
    componentDidMount() {
        
    }
    
    onSendClick(name, email, message, callback){
        const {dispatch} = this.props;
        inovateOSPageActions.addMessage(
            {name, email, message}, 
            done=>callback(done)
        )(dispatch);
    }
    nameMapper(name){
        switch(name){
            case "address" : return "Address";
            case "phone" : return "Phone";
            case "email" : return "Email";
            default : return name;
        }
    }
    render() {
        const {
            classes,
            [inovateOSUtilStrings.settings] : settings,
            [inovateOSUtilStrings.subheadImage] : subheadImage
        } = this.props;
        let contactItem;
        if(settings){
            // const {item} = settings.getFirstObjectByPropValue("name", "contactInfo") || {};
            contactItem = settings.find(item=>item.name === "contactInfo");
        }
        return (
            <div className={classes.root}>
                <Subheader
                    classes={{
                        root : classes.subheader,
                        overlay : classes.subContainer,
                    }}
                    title="Contact Us"
                    image_url={subheadImage}
                    />
                <div className={classNames(classes.container, classes.subContainer)}>
                    <Grid container spacing={2}>
                        <Grid className={classes.contactInfo} style={{padding : 10}} item xs={12} sm={6} md={6} lg={6} xl={6}>
                            <SimpleListBoard
                                cardHeaderProps={{
                                    titleTypographyProps : {
                                        style : {
                                            color : inovateOSUtil.getTheme().secondary,
                                        }
                                    }
                                }}
                                classes={{
                                    header : classes.header
                                }}
                                title="CONTACT US"
                                skip={["facebook", "instagram", "twitter"]}
                                data={contactItem ? contactItem.value : {}}
                                nameMapper={this.nameMapper.bind(this)}
                                valueMapper={(name, value)=>value}/>
                                
                        </Grid>
                        <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                            <ContactUsForm
                                onSendClick={this.onSendClick.bind(this)}
                                classes={{
                                    send : classes.send
                                }}/>
                        </Grid>
                    </Grid>
                </div>
            </div>
        );
    }
}


_InovateOSContactUs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSUtilReducer}) => ({
    [inovateOSUtilStrings.settings] : inovateOSUtilReducer[inovateOSUtilStrings.settings],
    [inovateOSUtilStrings.subheadImage] : inovateOSUtilReducer[inovateOSUtilStrings.subheadImage],
})


export const InovateOSContactUs = connect(mapStateToProps)(withStyles(style)(_InovateOSContactUs));
export {InovateOSContactUs as default}